const parents = $('Supabase → Inactive Parents').all().map(i => i.json);
const messagesRaw = $input.first().json.content?.[0]?.text || '[]';

let messages = [];
try {
  const cleaned = messagesRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  messages = JSON.parse(cleaned);
} catch (e) {
  messages = [{ raw: messagesRaw }];
}

return [{ json: {
  status: 'completed',
  workflow: '18_parent_engagement',
  inactive_count: parents.length,
  messages: Array.isArray(messages) ? messages : [messages],
  completedAt: new Date().toISOString()
} }];
